+//! Opacity stack for layered rendering.
+
+/// Stack of opacity values that multiply together.
+#[derive(Clone, Debug)]
+pub struct OpacityStack {
+    stack: Vec<f32>,
+    current: f32,
+}
+
+impl OpacityStack {
+    /// Create a new opacity stack with full opacity.
+    #[must_use]
+    pub fn new() -> Self {
+        Self {
+            stack: Vec::new(),
+            current: 1.0,
+        }
